import 'react-native-gesture-handler';
import React, { useEffect } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { AuthProvider, useAuth } from './src/context/AuthContext';
import AuthScreen from './src/screens/AuthScreen';
import HomeScreen from './src/screens/HomeScreen';
import { ActivityIndicator, View, StyleSheet } from 'react-native';
import { setupAxiosInterceptors } from './src/api/axiosInstance'; // Import the setup function

const Stack = createNativeStackNavigator();

function AppNavigator() {
  const { isAuthenticated, isLoading, accessToken, refreshAccessToken, logout } = useAuth();

  // Setup Axios interceptors once auth context is available
  useEffect(() => {
    // This function will be called by the interceptor to get the current access token
    const getAccessToken = () => accessToken;
    setupAxiosInterceptors(getAccessToken, refreshAccessToken, logout);
  }, [accessToken, refreshAccessToken, logout]); // Re-run if these functions/token change

  if (isLoading) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <Stack.Navigator screenOptions={{ headerShown: false }}>
      {isAuthenticated ? (
        <Stack.Screen name="Home" component={HomeScreen} />
      ) : (
        <Stack.Screen name="Auth" component={AuthScreen} />
      )}
    </Stack.Navigator>
  );
}

export default function App() {
  return (
    <NavigationContainer>
      <AuthProvider>
        <AppNavigator />
      </AuthProvider>
    </NavigationContainer>
  );
}

const styles = StyleSheet.create({
  loadingContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

