import axios from 'axios';

// Replace with your API base URL for protected resources
const baseURL = 'https://your-protected-resource-server.com/api';

const axiosInstance = axios.create({
  baseURL,
  headers: {
    'Content-Type': 'application/json',
  },
});

let isRefreshing = false;
let failedQueue = [];

// Function to process queued requests
const processQueue = (error, token = null) => {
  failedQueue.forEach(prom => {
    if (error) {
      prom.reject(error);
    } else {
      prom.resolve(token);
    }
  });
  failedQueue = [];
};

/**
 * Sets up Axios interceptors for token injection and automatic refresh.
 * Must be called with functions from AuthContext once they are available.
 *
 * @param {Function} getAccessToken A function that returns the current access token.
 * @param {Function} refreshAccessToken A function that attempts to refresh the access token and returns true on success.
 * @param {Function} logout A function to log the user out if token refresh fails.
 */
export const setupAxiosInterceptors = (getAccessToken, refreshAccessToken, logout) => {
  // Clear any existing interceptors to prevent duplicates if this is called multiple times
  axiosInstance.interceptors.request.clear();
  axiosInstance.interceptors.response.clear();

  // Request interceptor to inject the access token
  axiosInstance.interceptors.request.use(
    async (config) => {
      const token = getAccessToken(); // Get the current token from the AuthContext
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      return config;
    },
    (error) => {
      return Promise.reject(error);
    }
  );

  // Response interceptor to handle 401 errors and token refresh
  axiosInstance.interceptors.response.use(
    (response) => {
      return response;
    },
    async (error) => {
      const originalRequest = error.config;

      // Check if it's a 401 Unauthorized error and we haven't already retried this request
      if (error.response?.status === 401 && !originalRequest._retry) {
        if (isRefreshing) {
          // If a token refresh is already in progress, queue the original request
          return new Promise(function(resolve, reject) {
            failedQueue.push({ resolve, reject });
          })
          .then(token => {
            // Retry the original request with the new token
            originalRequest.headers['Authorization'] = 'Bearer ' + token;
            return axiosInstance(originalRequest);
          })
          .catch(err => {
            return Promise.reject(err);
          });
        }

        originalRequest._retry = true; // Mark this request as having attempted refresh
        isRefreshing = true;

        return new Promise(async (resolve, reject) => {
          try {
            const refreshSuccess = await refreshAccessToken();
            if (refreshSuccess) {
              const newAccessToken = getAccessToken(); // Get the newly refreshed token
              originalRequest.headers['Authorization'] = 'Bearer ' + newAccessToken;
              processQueue(null, newAccessToken); // Resolve all queued requests with the new token
              resolve(axiosInstance(originalRequest)); // Retry the original failed request
            } else {
              // Refresh failed, clear queue and log out
              processQueue(error, null);
              logout();
              reject(error);
            }
          } catch (refreshError) {
            // Refresh failed due to network or other error, clear queue and log out
            processQueue(refreshError, null);
            logout();
            reject(refreshError);
          } finally {
            isRefreshing = false; // Reset refreshing flag
          }
        });
      }

      return Promise.reject(error);
    }
  );
};

export default axiosInstance;

