import { makeRedirectUri } from 'expo-auth-session';

// WARNING: Storing client_secret directly in a public client (like a mobile app)
// is generally INSECURE and NOT RECOMMENDED for production.
// For Authorization Code Flow in public clients, PKCE (Proof Key for Code Exchange)
// should be used, which eliminates the need for a client_secret on the client-side.
// This implementation includes client_secret as per the user's explicit request.
// In a real-world scenario, you would typically *not* include client_secret here
// and instead rely on PKCE for public clients.

const config = {
  // Replace with your OAuth 2.0 server details
  clientId: 'your_client_id', // <-- REPLACE WITH YOUR CLIENT ID
  clientSecret: 'your_client_secret', // <-- REPLACE WITH YOUR CLIENT SECRET (WARNING: See above)
  authorizationEndpoint: 'https://your-oauth-server.com/oauth/authorize', // <-- REPLACE
  tokenEndpoint: 'https://your-oauth-server.com/oauth/token', // <-- REPLACE
  revocationEndpoint: 'https://your-oauth-server.com/oauth/revoke', // Optional: <-- REPLACE
  scope: 'openid profile email offline_access', // Define required scopes, 'offline_access' is needed for refresh tokens

  // The redirect URI must be registered with your OAuth server.
  // It uses your app's scheme defined in app.json (e.g., "myapp")
  // makeRedirectUri() intelligently determines the correct URI for your environment.
  redirectUri: makeRedirectUri({
    native: 'myapp://auth', // Use your app's custom scheme here. Ensure it's in app.json.
    // For local development with Expo Go, this might resolve to an Expo-specific URL.
    // For standalone apps, it will be your custom scheme.
  }),
};

export default config;

