import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import * as WebBrowser from 'expo-web-browser';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';
import config from '../config/oauthConfig';
import axios from 'axios';
// import { jwtDecode } from 'jwt-decode'; // Uncomment if you want to decode id_token

// Required for expo-web-browser to properly close after authentication
WebBrowser.maybeCompleteAuthSession();

const AuthContext = createContext(null);

const ACCESS_TOKEN_KEY = 'access_token';
const REFRESH_TOKEN_KEY = 'refresh_token';
const EXPIRES_IN_KEY = 'expires_in';
const TOKEN_OBTAINED_AT_KEY = 'token_obtained_at'; // Timestamp for when the token was obtained

export const AuthProvider = ({ children }) => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [expiresIn, setExpiresIn] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true); // Initial loading state for token check/loading
  const [user, setUser] = useState(null); // Optional: Store user info (e.g., from id_token)
  const tokenRefreshTimeout = useRef(null); // Ref to hold the timeout ID for token refresh

  // --- Helper Functions for Token Management ---
  const storeTokens = useCallback(async (access, refresh, expires) => {
    await SecureStore.setItemAsync(ACCESS_TOKEN_KEY, access);
    await SecureStore.setItemAsync(REFRESH_TOKEN_KEY, refresh);
    await SecureStore.setItemAsync(EXPIRES_IN_KEY, String(expires));
    await SecureStore.setItemAsync(TOKEN_OBTAINED_AT_KEY, String(Date.now()));
    setAccessToken(access);
    setRefreshToken(refresh);
    setExpiresIn(expires);
    setIsAuthenticated(true);
    console.log('Tokens stored successfully.');
  }, []);

  const clearTokens = useCallback(async () => {
    await SecureStore.deleteItemAsync(ACCESS_TOKEN_KEY);
    await SecureStore.deleteItemAsync(REFRESH_TOKEN_KEY);
    await SecureStore.deleteItemAsync(EXPIRES_IN_KEY);
    await SecureStore.deleteItemAsync(TOKEN_OBTAINED_AT_KEY);
    setAccessToken(null);
    setRefreshToken(null);
    setExpiresIn(null);
    setIsAuthenticated(false);
    setUser(null);
    if (tokenRefreshTimeout.current) {
      clearTimeout(tokenRefreshTimeout.current);
    }
    console.log('Tokens cleared.');
  }, []);

  // Function to refresh the access token using the refresh token
  const refreshAccessToken = useCallback(async () => {
    if (!refreshToken) {
      console.warn('No refresh token available to refresh. Forcing logout.');
      await clearTokens();
      return false;
    }

    console.log('Attempting to refresh access token...');
    try {
      const response = await axios.post(
        config.tokenEndpoint,
        new URLSearchParams({
          grant_type: 'refresh_token',
          client_id: config.clientId,
          client_secret: config.clientSecret, // WARNING: See oauthConfig.js
          refresh_token: refreshToken,
          scope: config.scope, // Re-request desired scopes
        }).toString(),
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
        }
      );

      const {
        access_token: newAccessToken,
        refresh_token: newRefreshToken, // Refresh tokens can be rotated by the server
        expires_in: newExpiresIn,
      } = response.data;

      console.log('Access token refreshed successfully.');
      await storeTokens(newAccessToken, newRefreshToken || refreshToken, newExpiresIn); // Use new refresh token if provided
      return true;
    } catch (error) {
      console.error('Error refreshing token:', error.response?.data || error.message);
      await clearTokens(); // Force logout on refresh failure
      return false;
    }
  }, [refreshToken, storeTokens, clearTokens]);

  // Schedules the next token refresh before the current one expires
  const scheduleTokenRefresh = useCallback((expiresInSeconds) => {
    if (tokenRefreshTimeout.current) {
      clearTimeout(tokenRefreshTimeout.current);
    }
    if (!expiresInSeconds || expiresInSeconds <= 0) {
      console.warn('Invalid expires_in value for scheduling refresh.');
      return;
    }

    // Refresh a reasonable amount of time before expiry (e.g., 5 minutes)
    const refreshBuffer = 300; // 5 minutes in seconds
    const refreshDelayMs = Math.max(0, (expiresInSeconds - refreshBuffer) * 1000);

    if (refreshDelayMs > 0) {
      console.log(`Scheduling token refresh in ${refreshDelayMs / 1000} seconds.`);
      tokenRefreshTimeout.current = setTimeout(async () => {
        const success = await refreshAccessToken();
        if (!success) {
          console.error('Failed to automatically refresh token. User will be logged out.');
        }
      }, refreshDelayMs);
    } else {
      console.warn('Token expires too soon or already expired. Attempting immediate refresh.');
      refreshAccessToken(); // Attempt immediate refresh if buffer is not possible
    }
  }, [refreshAccessToken]);


  // --- Initial Token Loading and Refresh Logic on App Start ---
  useEffect(() => {
    const loadAndValidateTokens = async () => {
      try {
        const storedAccessToken = await SecureStore.getItemAsync(ACCESS_TOKEN_KEY);
        const storedRefreshToken = await SecureStore.getItemAsync(REFRESH_TOKEN_KEY);
        const storedExpiresIn = await SecureStore.getItemAsync(EXPIRES_IN_KEY);
        const storedObtainedAt = await SecureStore.getItemAsync(TOKEN_OBTAINED_AT_KEY);

        if (storedAccessToken && storedRefreshToken && storedExpiresIn && storedObtainedAt) {
          const expiresAt = parseInt(storedObtainedAt, 10) + parseInt(storedExpiresIn, 10) * 1000;
          const currentTime = Date.now();

          // Check if access token is still valid (with a small buffer)
          const bufferTime = 60 * 1000; // 1 minute buffer for network latency/clock skew
          if (expiresAt > currentTime + bufferTime) {
            console.log('Existing access token is valid from storage.');
            setAccessToken(storedAccessToken);
            setRefreshToken(storedRefreshToken);
            setExpiresIn(parseInt(storedExpiresIn, 10));
            setIsAuthenticated(true);
            scheduleTokenRefresh(parseInt(storedExpiresIn, 10)); // Schedule next refresh
          } else {
            console.log('Existing access token expired or near expiry. Attempting to refresh...');
            // Temporarily set refreshToken for the refreshAccessToken function to use
            setRefreshToken(storedRefreshToken);
            const success = await refreshAccessToken();
            if (success) {
              console.log('Tokens refreshed successfully on startup.');
              // State updated and next refresh scheduled by refreshAccessToken
            } else {
              console.log('Failed to refresh on startup. Clearing tokens.');
              await clearTokens();
            }
          }
        } else {
          console.log('No existing tokens found in secure store.');
          await clearTokens(); // Ensure all token states are clean if partial data exists
        }
      } catch (error) {
        console.error('Failed to load or validate tokens from secure store:', error);
        await clearTokens();
      } finally {
        setIsLoading(false); // Authentication check complete
      }
    };
    loadAndValidateTokens();

    // Cleanup timeout on component unmount
    return () => {
      if (tokenRefreshTimeout.current) {
        clearTimeout(tokenRefreshTimeout.current);
      }
    };
  }, [clearTokens, refreshAccessToken, scheduleTokenRefresh]);


  // --- OAuth Login Flow using expo-auth-session ---
  const authRequest = AuthSession.useAuthRequest(
    {
      clientId: config.clientId,
      redirectUri: config.redirectUri,
      scopes: config.scope.split(' '), // expo-auth-session expects an array of scopes
      extraParams: {
        client_secret: config.clientSecret, // WARNING: See oauthConfig.js
      },
      // PKCE (Proof Key for Code Exchange) is enabled by default for useAuthRequest,
      // which is best practice for public clients like mobile apps.
      // This means the client_secret is technically not strictly required by OAuth servers
      // when PKCE is present for token exchange, but it's included here per user request.
    },
    {
      authorizationEndpoint: config.authorizationEndpoint,
      tokenEndpoint: config.tokenEndpoint,
      revocationEndpoint: config.revocationEndpoint,
    }
  );

  const login = useCallback(async () => {
    try {
      if (!authRequest[0]) {
        console.error('Auth request not ready. Please ensure promptAsync is defined.');
        return;
      }

      setIsLoading(true); // Indicate loading during the login process
      console.log('Initiating OAuth login flow...');
      const authResult = await authRequest[0].promptAsync();

      if (authResult.type === 'success' && authResult.params.code) {
        console.log('Authorization successful. Exchanging code for tokens...');
        const tokenResponse = await axios.post(
          config.tokenEndpoint,
          new URLSearchParams({
            grant_type: 'authorization_code',
            client_id: config.clientId,
            client_secret: config.clientSecret, // WARNING: See oauthConfig.js
            code: authResult.params.code,
            redirect_uri: config.redirectUri,
            code_verifier: authRequest[0].codeVerifier, // PKCE parameter provided by expo-auth-session
          }).toString(),
          {
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
          }
        );

        const {
          access_token,
          refresh_token,
          expires_in,
          id_token // Optional: if OpenID Connect is used, this contains user info
        } = tokenResponse.data;

        await storeTokens(access_token, refresh_token, expires_in);

        // Optionally decode ID token for user information
        // if (id_token) {
        //   const decodedIdToken = jwtDecode(id_token); // Requires 'jwt-decode' package
        //   setUser(decodedIdToken);
        //   console.log('User info from ID Token:', decodedIdToken);
        // } else {
        //   // If no ID token, you might fetch user info from a /userinfo endpoint
        //   // or assume user info is not needed directly by the client.
        // }
        console.log('Login successful. Tokens stored and state updated.');
      } else if (authResult.type !== 'dismiss') {
        // Log errors other than user dismissing the browser
        console.error('Authentication failed or was cancelled:', authResult.type, authResult.error?.message);
        await clearTokens();
      } else {
        console.log('Authentication flow dismissed by user.');
      }
    } catch (error) {
      console.error('Error during login process:', error.response?.data || error.message);
      await clearTokens(); // Clear tokens on any login error
    } finally {
      setIsLoading(false); // Finish loading
    }
  }, [authRequest, clearTokens, storeTokens]);

  const logout = useCallback(async () => {
    console.log('Logging out...');
    try {
      if (config.revocationEndpoint && accessToken) {
        // Optional: Revoke token on the OAuth server
        // This is good practice to invalidate the token immediately server-side
        console.log('Attempting to revoke token on server...');
        await axios.post(
          config.revocationEndpoint,
          new URLSearchParams({
            token: accessToken,
            client_id: config.clientId,
            client_secret: config.clientSecret, // WARNING: See oauthConfig.js
            token_type_hint: 'access_token', // Indicate that we are revoking an access token
          }).toString(),
          {
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
          }
        );
        console.log('Access token revoked on server.');
      }
      await clearTokens(); // Clear local tokens regardless of server revocation success
      console.log('Logged out successfully.');
    } catch (error) {
      console.error('Error during logout/token revocation:', error.response?.data || error.message);
      // Even if server revocation fails, ensure local tokens are cleared for user experience
      await clearTokens();
      console.warn('Local tokens cleared despite server revocation error.');
    }
  }, [accessToken, clearTokens]);


  const authContextValue = {
    accessToken,
    refreshToken,
    isAuthenticated,
    isLoading,
    user,
    login,
    logout,
    refreshAccessToken, // Expose refresh function for interceptors
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

